const URL = 'https://practice-papers.onrender.com/chapter/deleteChapter/'

const deleteChapter = (chapterID, setserverOperationError, setServerOperationLoading, navigate, questionTypeID, unitID, questionTypeName) => {
    setServerOperationLoading(true)
    fetch(`${URL}${chapterID}/${unitID}`, {
        method: 'delete',
        headers: { 'Content-Type': 'application/json' },
    })
        .then((response) => response.json())
        .then((responseJson) => {
            if (responseJson.message === 'success') {
                navigate(`/unit/${questionTypeName}/${questionTypeID}`)
                setServerOperationLoading(false)
                setserverOperationError(null)
            } else {
                setserverOperationError(responseJson.message)
                setServerOperationLoading(false)
            }
        })
        .catch((error) => {
            setserverOperationError(error.message)
            setServerOperationLoading(false)
        });
}

export default deleteChapter;
